commands.examples:
SELECT DATE_FORMAT(NOW(), '%d/%m/%Y');  -- '15/01/2024'
SELECT DATE_FORMAT(created_at, '%W, %d %M %Y') FROM orders;
SELECT DATE_FORMAT(created_at, '%Y-%m') AS month FROM orders GROUP BY month;

SELECT DATE_ADD(NOW(), INTERVAL 7 DAY);
SELECT DATE_SUB(CURDATE(), INTERVAL 1 MONTH);
SELECT * FROM orders WHERE created_at > DATE_SUB(NOW(), INTERVAL 30 DAY);
SELECT * FROM subscriptions WHERE expires_at < DATE_ADD(NOW(), INTERVAL 7 DAY);

SELECT DATEDIFF('2024-12-31', '2024-01-01');  -- 365
SELECT DATEDIFF(NOW(), created_at) AS days_since FROM orders;
SELECT TIMESTAMPDIFF(HOUR, created_at, NOW()) AS hours_ago FROM orders;
SELECT TIMESTAMPDIFF(YEAR, birth_date, CURDATE()) AS age FROM users;

SELECT EXTRACT(YEAR FROM created_at) AS year FROM orders;
SELECT YEAR(created_at), MONTH(created_at) FROM orders;
SELECT DAYNAME(created_at) AS day_name FROM orders;
SELECT MONTHNAME(created_at) AS month_name FROM orders;
SELECT DAYOFWEEK(created_at) FROM orders;  -- 1=Sunday

SELECT STR_TO_DATE('15/01/2024', '%d/%m/%Y');
SELECT STR_TO_DATE('January 15, 2024', '%M %d, %Y');
INSERT INTO events (event_date) VALUES (STR_TO_DATE('2024-06-15 14:30', '%Y-%m-%d %H:%i'));
